---@type LazyPluginSpec
return {
    "dmtrKovalenko/fff.nvim",
    build = function()
        require("fff.download").download_or_build_binary()
    end,
    lazy = false, -- make fff initialize on startup

    -- fff-snacks.nvim must come after fff.nvim
    dependencies = {
        {
            "nikbrunner/fff-snacks.nvim",
            dev = true, -- use local version during development
            lazy = false, -- loaded by plugin/fff-snacks.lua on UIEnter
            keys = {
                { "<leader>ff", function() require("fff-snacks").find_files() end, desc = "FFF find files" },
                { "<leader>fw", function() require("fff-snacks").live_grep() end, desc = "FFF live grep" },
                {
                    mode = "v",
                    "<leader>fw",
                    function()
                        require("fff-snacks").grep_word()
                    end,
                    desc = "FFF grep word",
                },
                {
                    "<leader>fz",
                    function()
                        require("fff-snacks").live_grep({
                            grep_mode = { "fuzzy", "plain", "regex" },
                        })
                    end,
                    desc = "FFF live grep (fuzzy)",
                },
            },
            ---@type fff-snacks.Config
            opts = {},
        },
    },
}
